/* 比特彩票最优解 - 数位贪心算法 */
#include <bits/stdc++.h>
using namespace std;
using ll = long long;

int main() {
    int n;
    ll m;
    cin >> n >> m;
    vector<ll> a(n);
    for (auto& x : a) cin >> x;

    ll res = 0;
    // 从最高位到最低位逐位处理
    for (int bit = 60; bit >= 0; --bit) {
        // 尝试设置该位为1，检查是否可能
        ll candidate = res | (1LL << bit);
        if (candidate > m) continue;  // 不能超过m

        // 计算该位设置为1时的总贡献
        ll sum = 0;
        int cnt = 0;  // 记录有多少数实际使用了该位
        for (int i = 0; i < n; ++i) {
            // b_i必须 >= previous +1，所以我们按顺序分配最小的可能值
            ll min_val = (i == 0) ? 0 : (1LL << bit) + i;
            if (min_val > m) break;  // 无法满足递增条件

            if (a[i] > 0) {
                sum += a[i];  // 该位为1贡献正数
                cnt++;
            }
        }

        // 只有当该位贡献为正时才保留
        if (sum > 0) {
            res = candidate;
            // 更新a数组，减去已经确定的位的贡献
            for (int i = 0; i < n; ++i) {
                if (i < cnt && a[i] > 0) {
                    a[i] = 0;  // 这些数的更高位已被处理
                }
            }
        }
    }

    // 最后计算实际选择的数的popcount总和
    ll total = 0;
    for (int i = 0; i < n; ++i) {
        ll b = res + i;  // 构造严格递增序列
        if (b > m) b = m - (n - 1 - i);  // 处理边界情况
        total += __builtin_popcountll(b) * a[i];
    }
    cout << total << endl;

    return 0;
}

