题目标题：
问题 F: 最长回文
题目描述：
给定若干互不相同的非空字符串，你需要选择**两个**不同的字符串，将它们拼接，使得拼接后的字符串是回文串。求所有可能方案中，回文串的最大长度。

> 对于一个字符串 $s$ 其长度为 $m$，即 $s = s_1 s_2 \dots s_m$，其中 $s_i$ 表示字符串 $s$ 的第 $i$ 个字符。如果对于所有的 $i \in \{1, 2, \dots, m\}$，都有 $s_i = s_{m+1-i}$，则称字符串 $s$ 是一个**回文串**。
输入描述：
- 第一行输入整数 $n$ ($2 \leq n \leq 10^5$)，表示字符串数量。- 接下来 $n$ 行，每行输入一个由小写字母组成的非空字符串。- **数据保证**：- 所有字符串互不相同；- 所有字符串总长度不超过 $5 \times 10^5$；- 每个字符串长度至少为 1。
样例输入：
3
a
ab
ba
输出描述：
- 输出一个整数，表示能拼接出的最长回文串长度。若无解，输出 0。
样例输出：
4
提示：
可以拼接 ab + ba 或者 ba + ab ，都得到回文串，长度为 4

[待修复代码]
/* 最长回文拼接 - 使用字符串哈希优化查找 */
#include <bits/stdc++.h>
using namespace std;

bool is_palindrome(const string &s) {
    int l = 0, r = s.size() - 1;
    while (l < r) {
        if (s[l] != s[r]) return false;
        l++; r--;
    }
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<string> strs(n);
    unordered_set<string> str_set; // 存储所有字符串

    for (int i = 0; i < n; ++i) {
        cin >> strs[i];
        str_set.insert(strs[i]);
    }

    int max_len = 0;
    for (const auto &s : strs) {
        // 检查完全逆序匹配
        string rev(s.rbegin(), s.rend());
        if (str_set.count(rev) && rev != s) {
            max_len = max(max_len, (int)(s.size() + rev.size()));
        }

        // 检查部分逆序匹配
        // 情况1: t是s的前缀的逆序，且s的剩余部分是回文 (t + s是回文)
        for (int i = 1; i < s.size(); ++i) {
            string prefix = s.substr(0, i);
            string rev_prefix(prefix.rbegin(), prefix.rend());
            string remaining = s.substr(i);
            if (is_palindrome(remaining) && str_set.count(rev_prefix) && rev_prefix != s) {
                max_len = max(max_len, (int)(rev_prefix.size() + s.size()));
            }
        }

        // 情况2: t是s的后缀的逆序，且s的前面部分是回文 (s + t是回文)
        for (int i = 1; i < s.size(); ++i) {
            string suffix = s.substr(s.size() - i);
            string rev_suffix(suffix.rbegin(), suffix.rend());
            string remaining = s.substr(0, s.size() - i);
            if (is_palindrome(remaining) && str_set.count(rev_suffix) && rev_suffix != s) {
                max_len = max(max_len, (int)(s.size() + rev_suffix.size()));
            }
        }
    }

    cout << max_len << '\n';
    return 0;
}

